def main() -> None:
    saida = Path("data/raw/qle_dataset.jsonl")
    saida.parent.mkdir(parents=True, exist_ok=True)

    with saida.open("w", encoding="utf-8", newline="\n") as arquivo:
        for exemplo in EXEMPLOS:
            arquivo.write(json.dumps(exemplo, ensure_ascii=False) + "\n")

    print(f"Arquivo criado: {saida.resolve()}")
    print(f"Exemplos gravados: {len(EXEMPLOS)}")
    print(f"Tamanho: {saida.stat().st_size} bytes")

if __name__ == "__main__":
    main()
